// Build-time loader for the F2 dataset (generated by f2_predictions.export).
// Server components in a static export read the JSON from disk at build.

import { readFileSync } from "node:fs";
import { join } from "node:path";

import type { F2Data } from "@/types/f2";

let cache: F2Data | null = null;

export function getF2Data(): F2Data {
  if (cache) return cache;
  const path = join(process.cwd(), "public", "data", "f2.json");
  cache = JSON.parse(readFileSync(path, "utf-8")) as F2Data;
  return cache;
}

const TEAM_COLORS: Record<string, string> = {
  "ART Grand Prix": "#6b6b6b",
  "Prema Racing": "#E2001A",
  "MP Motorsport": "#F47C20",
  DAMS: "#0090D0",
  "Campos Racing": "#3a5bd0",
  "Invicta Racing": "#8E44AD",
  Hitech: "#9aa0a8",
  "Rodin Motorsport": "#00A19A",
  "Van Amersfoort Racing": "#FF5A00",
  Trident: "#2f7fd0",
  "AIX Racing": "#C0392B",
};

export function teamColor(team: string): string {
  return TEAM_COLORS[team] || "#1E9BD7";
}
